def reconcile(n_in, n_clean, n_quarantine):
    if n_in != n_clean + n_quarantine:
        raise SystemExit(1)
    return 0
print('ok', reconcile(10, 8, 2))
try:
    reconcile(10, 9, 0)
except SystemExit as e:
    print('fail closed exit', e.code)

