import csv, io
raw = "id,nombre\nC001,Ana\n,\nC003,Luis\n"
clean, quar = [], []
for i, row in enumerate(csv.DictReader(io.StringIO(raw)), start=1):
    if not row.get('id'):
        quar.append({'line': i, 'reason': 'missing_id', 'row': row})
    else:
        clean.append(row)
print('clean', clean)
print('quarantine', quar)

